const items = [];

for (const item of $input.all()) {
  const emailData = item.json;

  // Handle sender information (unchanged)
  let senderEmail = '';
  let senderName = '';

  if (emailData.from?.value?.[0]) {
    senderEmail = emailData.from.value[0].address || '';
    senderName = emailData.from.value[0].name || senderEmail;
  } else if (emailData.from?.text) {
    const emailMatch = emailData.from.text.match(/<([^>]+)>/) || 
                      emailData.from.text.match(/([^\s]+@[^\s]+)/);
    senderEmail = emailMatch ? emailMatch[1] : emailData.from.text;

    const nameMatch = emailData.from.text.match(/^([^<]+)/);
    senderName = nameMatch ? nameMatch[1].trim().replace(/\"/g, '') : senderEmail;
  }

  // Format date (unchanged)
  const receivedDate = new Date(emailData.date || emailData.receivedTime);
  const formattedDate = receivedDate.toLocaleString('en-US', {
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hour12: true
  });

  // FIXED CONTENT EXTRACTION
  let emailContent = '';

  // 1. First priority: Plain text version
  if (emailData.text) {
    emailContent = emailData.text;
  } 
  // 2. Second priority: HTML version (convert to plain text)
  else if (emailData.html) {
    emailContent = emailData.html
      .replace(/<style[^>]*>.*?<\/style>/gs, '')  // Remove CSS
      .replace(/<[^>]*>/g, ' ')                   // Strip HTML tags
      .replace(/\s+/g, ' ')                       // Collapse whitespace
      .trim();
  }
  // 3. Fallback to other possible fields
  else if (emailData.body || emailData.textPlain || emailData.textHtml) {
    emailContent = emailData.body || emailData.textPlain || emailData.textHtml;
  }

  // Truncate content if too long
  const maxContentLength = 5000;
  if (emailContent.length > maxContentLength) {
    emailContent = emailContent.substring(0, maxContentLength) + '... [truncated]';
  }

  // Create row data
  const rowData = {
    mailid: $input.first().json.id,
    mailThreadId: $input.first().json.threadId,
    date: formattedDate,
    senderName: senderName,
    senderEmail: senderEmail,
    subject: emailData.subject || 'No Subject',
    content: emailContent,
    labelIds: $input.first().json.labelIds
  };

  items.push({ json: rowData });
}

return items;

// --- STEP 1: Parse the Raw AI Output ---
const raw = $input.first().json.output;

// Clean up markdown (```json ... ```) if the AI added it
const cleaned = raw
  .replace(/```json/i, '')
  .replace(/```/g, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  // Fallback if parsing fails (prevents workflow crash)
  parsed = { category: "Error", entities: {}, parse_error: true };
}

// --- STEP 2: Handle Date Logic (The "Scheduler" Brain) ---
const entities = parsed.entities || {};

if (entities.event_start) {
  // A. Parse Start Time
  // Check if string is valid, otherwise use "Now"
  const startString = entities.event_start;
  const startDate = (startString && startString !== "null") ? new Date(startString) : new Date();

  // B. Calculate End Time Logic
  const endString = entities.event_end;
  // Check if endString is valid (not null, not "null", not empty)
  const isValidEnd = endString && endString !== "null" && endString !== "undefined" && typeof endString === 'string' && endString.trim() !== "";

  let endDate;
  if (isValidEnd) {
    endDate = new Date(endString);
  } else {
    // FALLBACK: Clone Start Date + 1 Hour
    endDate = new Date(startDate.getTime());
    endDate.setHours(endDate.getHours() + 1);
  }

  // C. Update the entities with standardized ISO strings
  entities.event_start = startDate.toISOString();
  entities.event_end = endDate.toISOString();

  // Optional: Add duration for debugging
  entities.duration_minutes = (endDate - startDate) / 60000;
}

// --- STEP 3: Return the Final Combined Object ---
// We pull email details from the *original* source (Code in JavaScript)
// NOTE: Ensure 'Code in JavaScript' is the correct node name for your source data
const sourceEmail = $('Code in JavaScript').first().json; 

return {
  email: sourceEmail,
  analysis: {
    ...parsed,
    parse_error: false
  }
};

const rawData = $input.first().json.content.parts[0].text;
const data = JSON.parse(rawData);

// 1. Parse the Start Time
const startDate = new Date(data.suggested_iso);

// 2. Calculate End Time (Start + 1 Hour)
const endDate = new Date(startDate.getTime());
endDate.setHours(endDate.getHours() + 1);

function toISTString(dateObj) {
  const options = { timeZone: 'Asia/Kolkata', hour12: false };
  const istString = dateObj.toLocaleString('sv-SE', options);
  return istString.replace(' ', 'T') + '+05:30';
}

