  free_slot: {
    suggested_time: data.suggested_iso,
    end_time: toISTString(endDate),
    readable_time: data.human_readable,
  }
};

// 1. Get the Routing Tag from your AI node's output
// We add "|| 'Fallback'" to handle cases where the AI might return null.
const routingTag = $input.first().json.analysis.entities.routing || "Fallback";

// 2. Paste your JSON Contact List here
const contactList = {
  "DevOps": {
    "name": "Alex Chen",
