    "phone": "+15550123344"
  },
  "Legal": {
    "name": "Legal Team",
    "email": "legal@somailer.com",
    "phone": "+15550198877"
  },
  "Fallback": {
    "name": "Admin",
    "email": "admin@somailer.com",
    "phone": "+15559990000"
  }
};

// 3. Find the matching contact data
// If the tag exists (e.g., "DevOps"), use it. If not, default to "Fallback".
const targetData = contactList[routingTag] || contactList["Fallback"];

// 4. Output ONLY the clean data needed for the next node
return {
  json: {
    routed_team: routingTag,
    recipient_name: targetData.name,
    recipient_email: targetData.email,
    recipient_phone: targetData.phone,

    // Pass through the original summary so you can use it in the message body
    alert_message: $input.first().json.analysis.summary
  }
};

